import React from 'react';
import { WEBSITE_CONTENT } from '@/data/data';

export const metadata = {
    title: WEBSITE_CONTENT.pagesMetadata.areas.title,
    description: WEBSITE_CONTENT.pagesMetadata.areas.description,
    keywords: WEBSITE_CONTENT.pagesMetadata.areas.keywords,
};

const areas = [
    "Adyar", "Anna Nagar", "Besant Nagar", "Chromepet",
    "Egmore", "Guindy", "Kilpauk", "Kodambakkam",
    "Mylapore", "Nungambakkam", "Porur", "Saidapet",
    "T. Nagar", "Tambaram", "Velachery", "Virugambakkam"
];

export default function AreasPage() {
    return (
        <main className="bg-light min-vh-100 pb-5">
            <section className="bg-white border-bottom py-5">
                <div className="container text-center">
                    <h1 className="display-5 fw-bold text-dark mb-3">Areas We Serve in Chennai</h1>
                    <p className="text-secondary mx-auto" style={{ maxWidth: '600px' }}>We currently provide home healthcare services across Chennai and nearby areas.</p>
                </div>
            </section>

            <section className="py-5 container">
                <div className="bg-dark text-white rounded-4 p-4 p-md-5 shadow-lg">
                    <h2 className="h3 fw-bold mb-4 border-start border-4 border-primary ps-3">Coverage List</h2>
                    <div className="row g-3">
                        {areas.map((area, index) => (
                            <div key={index} className="col-12 col-sm-6 col-md-3">
                                <div className="bg-white text-dark rounded py-2 px-3 fw-medium text-center h-100 d-flex align-items-center justify-content-center">
                                    {area}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="text-center mt-5">
                    <h3 className="h4 fw-bold text-dark mb-2">
                        If your area is not listed, please contact us to confirm service availability.
                    </h3>
                </div>
            </section>
        </main>
    );
}
